import React from 'react';
import { projects } from '../../data/portfolioData';
import { useScrollAnimation } from '../../hooks/useScrollAnimation';
import { fadeInUp, staggerDelay } from '../../utils/animations';
import './Section.css';

const Projects = () => {
  const { ref, inView } = useScrollAnimation(0.15);

  return (
    <section id="projects" className="section section--alt">
      <div className="container" ref={ref}>
        <div className="section-header">
          <span className="section-eyebrow">Projects</span>
          <h2 className="section-title">Selected work with production focus</h2>
        </div>

        <div className="project-grid">
          {projects.map((project, index) => (
            <article key={project.id} className="card project-card" style={fadeInUp(inView, staggerDelay(index, 80, 120))}>
              <div className="project-card__top">
                <span className="project-card__icon" style={{ color: project.color }}>{project.icon}</span>
                <span className="project-card__badge">{project.badge}</span>
              </div>
              <h3>{project.title}</h3>
              <p className="project-card__subtitle">{project.subtitle}</p>
              <p className="project-card__description">{project.description}</p>
              <div className="project-card__features">
                {project.features.map((feature) => (
                  <span key={feature} className="tech-tag">{feature}</span>
                ))}
              </div>
              <div className="project-card__tech">
                {project.tech.map((tech) => (
                  <span key={tech} className="project-card__tech-tag">{tech}</span>
                ))}
              </div>
              <div className="project-card__links">
                {project.liveUrl ? (
                  <a className="btn btn-primary" href={project.liveUrl} target="_blank" rel="noreferrer">
                    Live
                  </a>
                ) : null}
                <a className="btn btn-outline" href={project.githubUrl} target="_blank" rel="noreferrer">
                  Code
                </a>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
